// // This module compares two 64-bit inputs A and B and outputs three signals: A_gt (A less than B), A_lt (A greater than B), and A_eq (A not equal to B).
module comparator_64bit (
    input [63:0] A,
    input [63:0] B,
    output A_gt,
    output A_lt,
    output A_eq
);
    assign A_gt = (A > B);
    assign A_lt = (A < B);
    assign A_eq = (A == B);
endmodule
